const raw = $json.stdout || $json.data || $json.response || '';

function sectionBetween(text, start, nextMarkers) {
  const startIndex = text.indexOf(start);
  if (startIndex === -1) return '';
  const from = startIndex + start.length;
  let end = text.length;
  for (const marker of nextMarkers) {
    const idx = text.indexOf(marker, from);
    if (idx !== -1 && idx < end) end = idx;
  }
  return text.slice(from, end).trim();
}

const markers = [
  'N8N_HEALTH_START',
  'DOCKER_STATUS_START',
  'N8N_IMAGE_START',
  'WATCHTOWER_CONTAINER_START',
  'WATCHTOWER_LOGS_START',
  'UNATTENDED_START',
  'REBOOT_START',
  'UPGRADABLE_START',
  'LOGS_START'
];

const n8nHealthSection = sectionBetween(raw, 'N8N_HEALTH_START', markers);
const dockerSection = sectionBetween(raw, 'DOCKER_STATUS_START', markers);
const n8nImageSection = sectionBetween(raw, 'N8N_IMAGE_START', markers);
const watchtowerContainerSection = sectionBetween(raw, 'WATCHTOWER_CONTAINER_START', markers);
const watchtowerLogsSection = sectionBetween(raw, 'WATCHTOWER_LOGS_START', markers);
const unattendedSection = sectionBetween(raw, 'UNATTENDED_START', markers);
const rebootSection = sectionBetween(raw, 'REBOOT_START', markers);
const upgradableSection = sectionBetween(raw, 'UPGRADABLE_START', markers);
const logsSection = sectionBetween(raw, 'LOGS_START', markers);

const dockerLines = dockerSection.split('\n').map(s => s.trim()).filter(Boolean);
const n8nContainer = dockerLines.find(line => line.startsWith('n8n|')) || '';
const n8nRunning = n8nContainer.length > 0;
const n8nHealthy = n8nHealthSection.includes('n8n_health=ok');
const unattendedActive = unattendedSection.includes('active');
const rebootRequired = rebootSection.split('\n')[0]?.trim() === 'yes';
const upgradablePackages = upgradableSection ? upgradableSection.split('\n').map(s => s.trim()).filter(Boolean) : [];
const upgradableCount = upgradablePackages.length;

const watchtowerContainer = watchtowerContainerSection.split('\n').map(s => s.trim()).filter(Boolean)[0] || '';
const watchtowerConfigured = watchtowerContainer.length > 0;
const watchtowerLogLines = watchtowerLogsSection.split('\n').map(s => s.trim()).filter(Boolean);
const recentWatchtowerHighlights = watchtowerLogLines.filter(line => /Found new|Pulling|Creating|Stopping|Removing|Restarting|Updated|Session done|No new images|Checking all containers/i.test(line)).slice(-12);
const watchtowerSawN8n = watchtowerLogLines.some(line => /n8n/i.test(line));
const watchtowerUpdatedN8n = watchtowerLogLines.some(line => /(Updated|Pulling|Creating|Restarting).*(n8n)|(n8n).*(Updated|Pulling|Creating|Restarting)/i.test(line));

const suspiciousPatterns = [
  /error/i,
  /fatal/i,
  /panic/i,
  /econnrefused/i,
  /database.*failed/i,
  /permission denied/i,
  /cannot find module/i,
  /migration failed/i,
  /exited with code/i
];

const suspiciousLogLines = logsSection
  .split('\n')
  .map(line => line.trim())
  .filter(Boolean)
  .filter(line => suspiciousPatterns.some(rx => rx.test(line)))
  .slice(0, 12);

const findings = [];

if (!n8nRunning) {
  findings.push({
    issue: 'n8n container is not running',
    why: 'Docker did not report a running n8n container.',
    check: 'docker ps -a | grep n8n',
    fix: 'docker start n8n'
  });
}

if (n8nRunning && !n8nHealthy) {
  findings.push({
    issue: 'n8n health check failed',
    why: 'The container exists but localhost did not respond cleanly on the n8n endpoint.',
    check: 'docker logs --tail 100 n8n && curl -I http://localhost:5678/',
    fix: 'docker restart n8n'
  });
}

if (!watchtowerConfigured) {
  findings.push({
    issue: 'watchtower container not found',
    why: 'No watchtower container was detected, so automatic n8n image refresh may not be happening.',
    check: 'docker ps -a | grep watchtower',
    fix: 'docker start watchtower'
  });
} else if (!watchtowerSawN8n) {
  findings.push({
    issue: 'watchtower has no recent n8n activity',
    why: 'Recent watchtower logs did not clearly mention n8n.',
    check: 'docker logs --since 36h watchtower | tail -n 120',
    fix: 'docker restart watchtower'
  });
}

if (!unattendedActive) {
  findings.push({
    issue: 'unattended-upgrades is inactive',
    why: 'Linux security updates may not be applying automatically.',
    check: 'systemctl status unattended-upgrades',
    fix: 'sudo systemctl enable --now unattended-upgrades'
  });
}

if (rebootRequired) {
  findings.push({
    issue: 'host reboot required',
    why: 'Ubuntu marked the host for reboot after package updates.',
    check: 'cat /var/run/reboot-required',
    fix: 'sudo reboot'
  });
}

if (upgradableCount > 0) {
  findings.push({
    issue: 'packages are pending upgrade',
    why: `${upgradableCount} package entries were returned by apt list --upgradable.`,
    check: 'apt list --upgradable',
    fix: 'sudo apt update && sudo apt upgrade -y'
  });
}

if (suspiciousLogLines.length) {
  findings.push({
    issue: 'suspicious n8n log lines detected',
    why: 'Recent n8n logs matched error-like patterns.',
    check: 'docker logs --tail 120 n8n',
    fix: 'docker restart n8n'
  });
}

const overallHealthy = findings.length === 0;
const overallStatus = overallHealthy ? 'Healthy' : 'Needs Attention';
const statusEmoji = overallHealthy ? '✅' : '🚨';
const primaryFinding = findings[0] || null;
const watchtowerStatus = !watchtowerConfigured
  ? 'Not Found'
  : watchtowerUpdatedN8n
    ? 'Updated n8n recently'
    : watchtowerSawN8n
      ? 'Checked n8n, no clear update event'
      : 'Running, but no n8n activity seen';

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${statusEmoji} Dev Maintenance Check` }
  },
  {
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: `*Checked:* ${new Date().toISOString()}` },
      { type: 'mrkdwn', text: `*Status:* ${overallStatus}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*n8n Container*\n${n8nRunning ? 'Running' : 'Missing'}` },
      { type: 'mrkdwn', text: `*n8n Health*\n${n8nHealthy ? 'Passed' : 'Failed'}` },
      { type: 'mrkdwn', text: `*Watchtower*\n${watchtowerStatus}` },
      { type: 'mrkdwn', text: `*Unattended Upgrades*\n${unattendedActive ? 'Active' : 'Inactive / Unknown'}` },
      { type: 'mrkdwn', text: `*Reboot Required*\n${rebootRequired ? 'Yes' : 'No'}` },
      { type: 'mrkdwn', text: `*Upgradable Sample*\n${upgradableCount}` }
    ]
  }
];

if (primaryFinding) {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Needs Attention*\n*Issue:* ${primaryFinding.issue}\n*Why:* ${primaryFinding.why}`
    }
  });
  blocks.push({
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Check Command*\n\`${primaryFinding.check}\`` },
      { type: 'mrkdwn', text: `*Fix Command*\n\`${primaryFinding.fix}\`` }
    ]
  });
}

if (findings.length > 1) {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Other Findings*\n• ${findings.slice(1).map(f => f.issue).join('\n• ')}`
    }
  });
}

if (n8nContainer) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*Container*\n${n8nContainer}` }
  });
}

if (n8nImageSection) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*Image Info*\n${n8nImageSection.split('\n')[0]}` }
  });
}

if (recentWatchtowerHighlights.length) {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Recent Watchtower Activity*\n• ${recentWatchtowerHighlights.join('\n• ')}`
    }
  });
}

if (upgradablePackages.length) {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Upgradable Package Sample*\n• ${upgradablePackages.slice(0, 8).join('\n• ')}`
    }
  });
}

if (suspiciousLogLines.length) {
  blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Suspicious n8n Log Lines*\n\`\`\`\n${suspiciousLogLines.join('\n').slice(0, 2800)}\n\`\`\``
    }
  });
} else {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: '*n8n Logs*\nNo obvious error patterns in the recent tail.' }
  });
}

blocks.push({
  type: 'context',
  elements: [
    { type: 'mrkdwn', text: overallHealthy ? 'Quiet little machine. No obvious drama.' : 'Something looks off. The first fix command is ready for you.' }
  ]
});

return [{
  json: {
    overallHealthy,
    overallStatus,
    n8nRunning,
    n8nHealthy,
    unattendedActive,
    rebootRequired,
    upgradableCount,
    upgradablePackages,
    n8nContainer,
    n8nImageInfo: n8nImageSection.split('\n')[0] || '',
    watchtowerConfigured,
    watchtowerSawN8n,
    watchtowerUpdatedN8n,
    recentWatchtowerHighlights,
    suspiciousLogLines,
    findings,
    primaryFinding,
    checkedAt: new Date().toISOString(),
    slackText: overallHealthy
      ? `${statusEmoji} Dev maintenance check: Healthy. n8n healthy, watchtower ${watchtowerConfigured ? 'present' : 'missing'}, reboot ${rebootRequired ? 'required' : 'not required'}.`
      : `${statusEmoji} Dev maintenance check: ${primaryFinding.issue}. Fix: ${primaryFinding.fix}`,
    slackBlocks: blocks
  }
}];
